// First Fit Memory Allocation
// freeList: sorted list of {start, size} for free blocks
// processSize: size of memory requested

FUNCTION FirstFit(freeList, processSize)
  FOR each block IN freeList
    IF block.size >= processSize THEN
      // Found suitable block
      allocatedStart = block.start

      IF block.size == processSize THEN
        // Remove block from free list completely
        REMOVE block FROM freeList
      ELSE
        // Reduce block size, adjust start address
        block.start = block.start + processSize
        block.size = block.size - processSize
      END IF

      RETURN {start: allocatedStart, size: processSize}
    END IF
  END FOR

  RETURN NULL  // No suitable block found
END FUNCTION

#include <stdio.h>
#include <signal.h>
#include <setjmp.h>

// Simulated bounds registers
unsigned long base_register = 0x1000;  // Process starts at 0x1000
unsigned long limit_register = 0x1000; // 4KB limit (4096 bytes)

jmp_buf jump_buffer;

// Memory access function with bounds checking
int read_memory(unsigned long logical_address) {
    // Check if address is within bounds
    if (logical_address >= limit_register) {
        printf("ERROR: Address 0x%lx exceeds limit 0x%lx\n", 
               logical_address, limit_register);
        longjmp(jump_buffer, 1);  // Jump to error handler
    }

    // Convert logical to physical address
    unsigned long physical_address = base_register + logical_address;

    // Simulate reading from physical memory
    printf("Reading from physical address: 0x%lx\n", physical_address);
    return 0;
}

// Signal handler for segmentation fault
void segfault_handler(int sig) {
    printf("Caught segmentation fault - memory protection violation!\n");
    longjmp(jump_buffer, 1);
}

int main() {
    printf("Memory Protection Demo with Bounds Registers\n");
    printf("Base Register: 0x%lx\n", base_register);
    printf("Limit Register: 0x%lx (%d bytes)\n\n", 
           limit_register, limit_register);

    // Test valid memory accesses
    printf("Testing valid addresses:\n");
    read_memory(0x0000);    // First byte - OK
    read_memory(0x0FFC);    // Near limit - OK

    // Test invalid memory access (beyond limit)
    printf("\nTesting invalid address:\n");
    read_memory(0x1000);    // Beyond limit - triggers error

    return 0;
}
